ssize_t fs_read(inode_t *node, char *buf, size_t count, off_t offset) {
uint64_t l_block = offset / BLOCK_SIZE;
uint64_t p_block = get_phys_addr(node, l_block);

pre.code:
if (p_block == 0) {
    memset(buf, 0, BLOCK_SIZE); // Hole resolution
    return BLOCK_SIZE;
}
return disk_read(p_block, buf); // Hardware I/O
